ALTER TABLE public.page_blocks DROP CONSTRAINT IF EXISTS page_blocks_position_check;
ALTER TABLE public.page_blocks ADD CONSTRAINT page_blocks_position_check CHECK (position IN ('before', 'after', 'full'));

INSERT INTO public.page_blocks (page_key, position, blocks)
VALUES ('over-ons', 'full', '[{"id": "5d61d81f-8d2b-401d-a10c-6c70a279bef0", "type": "hero", "props": {"title": "Over Ons", "subtitle": "Loyaltygroup B.V. — uw partner voor op maat gemaakte loyaliteitsoplossingen.", "bgColor": "gradient", "textColor": "light", "ctaLabel": "", "ctaLink": ""}}, {"id": "9f43a71b-8d60-4965-a91c-1f3fe1b6182b", "type": "heading", "props": {"text": "Wie zijn wij?", "level": 2, "align": "left", "marginTop": 40}}, {"id": "8d00919e-2c1f-4297-a056-4d1d5b3b798c", "type": "paragraph", "props": {"text": "Loyaltygroup B.V. is een Nederlands softwarebedrijf gespecialiseerd in het ontwikkelen van spaarsystemen en loyaliteitsprogramma''s. Wij werken voor zowel gemeenten als commerciële organisaties.", "align": "left"}}, {"id": "df2c8938-fa4d-45cf-bd9f-9b2621bb5c0d", "type": "paragraph", "props": {"text": "Wat ons onderscheidt is dat wij alles in eigen huis ontwikkelen. Ons team van ervaren ontwikkelaars bouwt elk systeem volledig op maat, zonder gebruik te maken van standaard templates of externe partijen.", "align": "left"}}, {"id": "1a9f70db-0064-49fc-be11-4a3e34dbe107", "type": "paragraph", "props": {"text": "Dankzij onze flexibele aanpak en diepgaande technische kennis kunnen wij snel inspelen op veranderende wensen en nieuwe mogelijkheden bieden die standaardoplossingen niet kunnen leveren.", "align": "left"}}, {"id": "320d5ee7-40be-4ec5-8c01-909b2c8115ff", "type": "heading", "props": {"text": "Onze Waarden", "level": 2, "align": "center", "marginTop": 60}}, {"id": "2fd00c58-4d13-4465-8828-116ce9f5e6da", "type": "row", "props": {"columns": 2, "gap": 24, "padding": "small", "bgColor": "background", "verticalAlign": "start"}, "children": [[{"id": "84795d30-8804-4252-96d9-040175d884bf", "type": "icon_card", "props": {"icon": "Code", "title": "In-house Ontwikkeling", "description": "Al onze systemen worden volledig in eigen huis ontwikkeld door ons ervaren team. Geen outsourcing, volledige controle over kwaliteit.", "iconColor": "primary"}}], [{"id": "a77924fa-3a1d-4273-bd95-7fbfcc7742db", "type": "icon_card", "props": {"icon": "Users", "title": "Klantgericht", "description": "Wij luisteren naar uw wensen en vertalen die naar een oplossing die perfect aansluit bij uw organisatie en doelgroep.", "iconColor": "primary"}}]]}, {"id": "497fcb56-92a3-4be6-b4a9-7f888ceed6ca", "type": "row", "props": {"columns": 2, "gap": 24, "padding": "small", "bgColor": "background", "verticalAlign": "start"}, "children": [[{"id": "633388b6-12cb-4be2-a906-5082d8b1854a", "type": "icon_card", "props": {"icon": "Heart", "title": "Passie voor Technologie", "description": "Ons team bestaat uit gepassioneerde ontwikkelaars die altijd op zoek zijn naar de beste en meest innovatieve oplossingen.", "iconColor": "primary"}}], [{"id": "ae67c7a7-3fc5-4da3-9691-03abc6d352d0", "type": "icon_card", "props": {"icon": "Shield", "title": "Betrouwbaar & Veilig", "description": "Veiligheid en betrouwbaarheid staan centraal in alles wat wij doen. Onze systemen voldoen aan de hoogste standaarden.", "iconColor": "primary"}}]]}]'::jsonb)
ON CONFLICT (page_key, position) DO UPDATE SET blocks = EXCLUDED.blocks, updated_at = now();